#include <numeric>
#include <bits/stdc++.h>
using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

class Solution {
public:
    vector<int> sortedVals;
    int floorInBST(TreeNode* root, int key) {
        // root is unused; we rely on sortedVals
        auto it = upper_bound(sortedVals.begin(), sortedVals.end(), key);
        if (it == sortedVals.begin()) return -1;
        --it;
        return *it;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    if (!(cin >> n)) return 0;
    vector<int> vals(n);
    for (int i = 0; i < n; ++i) cin >> vals[i];
    int q; cin >> q;
    vector<int> queries(q);
    for (int i = 0; i < q; ++i) cin >> queries[i];
    Solution sol;
    sol.sortedVals = vals;
    sort(sol.sortedVals.begin(), sol.sortedVals.end());
    // root is not needed; pass nullptr
    for (int i = 0; i < q; ++i) {
        int ans = sol.floorInBST(nullptr, queries[i]);
        cout << ans;
        if (i + 1 < q) cout << '\n';
    }
    return 0;
}
